1	interface QuoteStep {
2	  op: "quote";
3	  items: { type: string }[];
4	}
5	
6	interface Scenario {
7	  customer: { yearsWithMHPCO: number };
8	  steps: QuoteStep[];
9	}
10	
11	const BASE_PREMIUM: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  rune: 25,
17	};
18	
19	const FIRST_INSURANCE_RATE = 0.1;
20	const PROCESSING_FEE = 5;
21	
22	const RUNE_BLOCK_PREMIUM = 60;
23	
24	const runesBasePremium = (runeCount: number): number =>
25	  runeCount === 3 ? RUNE_BLOCK_PREMIUM : runeCount * BASE_PREMIUM.rune;
26	
27	const policyBasePremium = (items: { type: string }[]): number => {
28	  const runeCount = items.filter((item) => item.type === "rune").length;
29	  const nonRuneBase = items
30	    .filter((item) => item.type !== "rune")
31	    .reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
32	  return runesBasePremium(runeCount) + nonRuneBase;
33	};
34	
35	const quotePremium = (step: QuoteStep): number => {
36	  const policyBase = policyBasePremium(step.items);
37	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
38	  return Math.ceil(policyBase + firstInsurance + PROCESSING_FEE);
39	};
40	
41	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
42	  return {
43	    results: scenario.steps.map((step) => ({ premium: quotePremium(step) })),
44	  };
45	};
